; ヤネクの森

name = ヤネクの森・霧の谷
insideName = Mist Valley
level = 20
bgm = field
external = s:4
isOutdoor = true
shadow = light
sky = mistysea
blank = rock
effect = BE_fog

; 画像パーツ
━ = rockw
〓 = wood
　 = soilw
❖ = soilw
☗ = gatew
⑴ = bulletin
⑵ = empty
⑷ = bulletin

; 敵情報
maxGroups = 2
monsters = バルキリー,チャンピオン,ユニコーン,ファントム

; 移動ポイント
(A) = map:ヤネクの森・トンネル, x:9, y:11, way:w, symbol:cave, ask:Go to the next map?
(B) = map:ヤネクの森・トンネル, x:9, y:9, way:w, symbol:cave, ask:Go to the next map?
(C) = map:神の山１Ｆ, x:16, y:16, way:s, symbol:movev, ask:Go to the next map?

; 宝箱
box[1] = 破魔の短剣_u,経験のコイン（中）
box[2] = マジカルボートの巻物,経験のコイン（中）

